import { describe, it, expect } from 'vitest';
import { readFileSync, existsSync } from 'fs';
import { parse as parseYaml } from 'yaml';
import { resolve } from 'path';

const COMPOSE_PATH = resolve(__dirname, '../../docker-compose.yml');
const OVERRIDE_PATH = resolve(__dirname, '../../docker-compose.override.yml');
const CADDYFILE_PATH = resolve(__dirname, '../../Caddyfile');
const ENV_EXAMPLE_PATH = resolve(__dirname, '../../.env.example');

function loadCompose(): Record<string, any> {
  const raw = readFileSync(COMPOSE_PATH, 'utf-8');
  return parseYaml(raw);
}

function loadOverride(): Record<string, any> {
  const raw = readFileSync(OVERRIDE_PATH, 'utf-8');
  return parseYaml(raw);
}

function readCaddyfile(): string {
  return readFileSync(CADDYFILE_PATH, 'utf-8');
}

function readEnvExample(): string {
  return readFileSync(ENV_EXAMPLE_PATH, 'utf-8');
}

// Helper: get network names for a service (handles array or object format)
function getServiceNetworks(service: Record<string, any>): string[] {
  const nets = service?.networks;
  if (!nets) return [];
  if (Array.isArray(nets)) return nets;
  if (typeof nets === 'object') return Object.keys(nets);
  return [];
}

// =============================================================================
// REQ-A01: Dual Network Segmentation
// =============================================================================
describe('REQ-A01: Dual Network Segmentation', () => {
  it('T-A01: networks section defines exactly 2 networks (app, langfuse)', () => {
    // GIVEN the docker-compose.yml networks section
    // WHEN inspected
    // THEN it defines exactly two networks: app and langfuse
    const compose = loadCompose();
    const networkNames = Object.keys(compose.networks || {});
    expect(networkNames).toHaveLength(2);
    expect(networkNames).toContain('app');
    expect(networkNames).toContain('langfuse');
  });

  it('T-A02: app network has driver: bridge', () => {
    // GIVEN the docker-compose.yml networks section
    // WHEN the app network is inspected
    // THEN its driver is bridge
    const compose = loadCompose();
    expect(compose.networks.app.driver).toBe('bridge');
  });

  it('T-A03: langfuse network has driver: bridge', () => {
    // GIVEN the docker-compose.yml networks section
    // WHEN the langfuse network is inspected
    // THEN its driver is bridge
    const compose = loadCompose();
    expect(compose.networks.langfuse.driver).toBe('bridge');
  });

  it('T-A04: frontend service networks contains only app', () => {
    // GIVEN service frontend
    // WHEN its network configuration is inspected
    // THEN it is attached only to the app network
    const compose = loadCompose();
    const nets = getServiceNetworks(compose.services.frontend);
    expect(nets).toEqual(['app']);
  });

  it('T-A05: libsql service networks contains only app', () => {
    // GIVEN service libsql
    // WHEN its network configuration is inspected
    // THEN it is attached only to the app network
    const compose = loadCompose();
    const nets = getServiceNetworks(compose.services.libsql);
    expect(nets).toEqual(['app']);
  });

  it('T-A06: langfuse-web networks contains only langfuse', () => {
    // GIVEN service langfuse-web
    // WHEN its network configuration is inspected
    // THEN it is attached only to the langfuse network
    const compose = loadCompose();
    const nets = getServiceNetworks(compose.services['langfuse-web']);
    expect(nets).toEqual(['langfuse']);
  });

  it('T-A07: langfuse-worker networks contains only langfuse', () => {
    // GIVEN service langfuse-worker
    // WHEN its network configuration is inspected
    // THEN it is attached only to the langfuse network
    const compose = loadCompose();
    const nets = getServiceNetworks(compose.services['langfuse-worker']);
    expect(nets).toEqual(['langfuse']);
  });

  it('T-A08: clickhouse, redis, minio, langfuse-postgres networks contain only langfuse', () => {
    // GIVEN services clickhouse, redis, minio, langfuse-postgres
    // WHEN their network configuration is inspected
    // THEN each is attached only to the langfuse network
    const compose = loadCompose();
    const langfuseOnlyServices = ['clickhouse', 'redis', 'minio', 'langfuse-postgres'];
    for (const svc of langfuseOnlyServices) {
      const nets = getServiceNetworks(compose.services[svc]);
      expect(nets, `${svc} should only be on langfuse network`).toEqual(['langfuse']);
    }
  });

  it('T-A01-NEG: old triage network does NOT exist', () => {
    // GIVEN the docker-compose.yml networks section
    // WHEN inspected
    // THEN there is no network named triage
    const compose = loadCompose();
    const networkNames = Object.keys(compose.networks || {});
    expect(networkNames).not.toContain('triage');
  });

  it.todo('MANUAL: network isolation — app-only service cannot resolve langfuse-only hostname');
});

