// REQ-A03: Docker Compose Override for Dev Mode
// =============================================================================
describe('REQ-A03: Docker Compose Override for Dev Mode', () => {
  it('T-A11: docker-compose.override.yml exists', () => {
    // GIVEN the project root
    // WHEN checking for docker-compose.override.yml
    // THEN the file exists
    expect(existsSync(OVERRIDE_PATH)).toBe(true);
  });

  it('T-A12: override defines a vite service', () => {
    // GIVEN the docker-compose.override.yml
    // WHEN its services are inspected
    // THEN a vite service is defined
    const override = loadOverride();
    expect(override.services).toHaveProperty('vite');
  });

  it('T-A13: vite service uses node:22-alpine image', () => {
    // GIVEN the vite service in docker-compose.override.yml
    // WHEN its image is inspected
    // THEN it uses node:22-alpine (or compatible node:22 variant)
    const override = loadOverride();
    const image = override.services.vite.image;
    expect(image).toMatch(/node:22/);
  });

  it('T-A14: vite service exposes port 5173', () => {
    // GIVEN the vite service in docker-compose.override.yml
    // WHEN its ports are inspected
    // THEN port 5173 is exposed
    const override = loadOverride();
    const ports = override.services.vite.ports || [];
    const portStrings = ports.map((p: any) => String(p));
    const has5173 = portStrings.some((p: string) => p.includes('5173'));
    expect(has5173).toBe(true);
  });

  it('T-A15: override sets FRONTEND_MODE=dev for Caddy/frontend', () => {
    // GIVEN the docker-compose.override.yml
    // WHEN the frontend service environment is inspected
    // THEN FRONTEND_MODE is set to dev
    const override = loadOverride();
    const frontendEnv = override.services?.frontend?.environment;
    if (Array.isArray(frontendEnv)) {
      expect(frontendEnv).toContain('FRONTEND_MODE=dev');
    } else if (typeof frontendEnv === 'object' && frontendEnv !== null) {
      expect(frontendEnv.FRONTEND_MODE).toBe('dev');
    } else {
      // Check if it's set on another service that controls Caddy
      expect(frontendEnv).toBeDefined();
    }
  });

  it('T-A16: override mounts source volumes for vite', () => {
    // GIVEN the vite service in docker-compose.override.yml
    // WHEN its volumes are inspected
    // THEN source code volumes are mounted
    const override = loadOverride();
    const volumes = override.services.vite.volumes || [];
    expect(volumes.length).toBeGreaterThan(0);
  });

  it('T-A17: override changes runtime command to tsx --watch', () => {
    // GIVEN the runtime service override in docker-compose.override.yml
    // WHEN its command is inspected
    // THEN it contains tsx --watch (or tsx watch)
    const override = loadOverride();
    const cmd = override.services?.runtime?.command;
    const cmdStr = Array.isArray(cmd) ? cmd.join(' ') : String(cmd || '');
    expect(cmdStr).toMatch(/tsx.*watch/i);
  });

  it('T-A03-NEG: base compose has no vite service (prod mode)', () => {
    // GIVEN the base docker-compose.yml (without override)
    // WHEN services are inspected
    // THEN no vite service exists
    const compose = loadCompose();
    expect(compose.services).not.toHaveProperty('vite');
  });

  it.todo('MANUAL: docker compose up auto-loads override and starts vite with HMR');
  it.todo('MANUAL: docker compose -f docker-compose.yml up skips override');
});

// =============================================================================
// REQ-A04: Caddyfile Environment Variable Switching
// =============================================================================
describe('REQ-A04: Caddyfile Environment Variable Switching', () => {
  it('T-A18: Caddyfile contains (static-frontend) snippet', () => {
    // GIVEN the Caddyfile
    // WHEN inspected
    // THEN it contains a (static-frontend) snippet definition
    const caddy = readCaddyfile();
    expect(caddy).toMatch(/\(static-frontend\)/);
  });

  it('T-A19: Caddyfile contains (dev-frontend) snippet', () => {
    // GIVEN the Caddyfile
    // WHEN inspected
    // THEN it contains a (dev-frontend) snippet definition
    const caddy = readCaddyfile();
    expect(caddy).toMatch(/\(dev-frontend\)/);
  });

  it('T-A20: static-frontend snippet includes root, try_files, file_server', () => {
    // GIVEN the static-frontend snippet in the Caddyfile
    // WHEN its content is inspected
    // THEN it contains root, try_files, and file_server directives
    const caddy = readCaddyfile();
    // Extract the static-frontend snippet block (heuristic: from snippet def to next snippet or closing brace)
    const staticMatch = caddy.match(/\(static-frontend\)[\s\S]*?\{([\s\S]*?)\}/);
    const snippet = staticMatch ? staticMatch[1] : '';
    expect(snippet).toMatch(/root/);
    expect(snippet).toMatch(/try_files/);
    expect(snippet).toMatch(/file_server/);
  });

  it('T-A21: dev-frontend snippet has reverse_proxy to vite:5173', () => {
    // GIVEN the dev-frontend snippet in the Caddyfile
    // WHEN its content is inspected
    // THEN it contains reverse_proxy to vite:5173
    const caddy = readCaddyfile();
    const devMatch = caddy.match(/\(dev-frontend\)[\s\S]*?\{([\s\S]*?)\}/);
    const snippet = devMatch ? devMatch[1] : '';
    expect(snippet).toMatch(/reverse_proxy.*vite:5173/);
  });

  it('T-A22: Caddyfile uses import {$FRONTEND_MODE:static}-frontend', () => {
    // GIVEN the Caddyfile
    // WHEN inspected
    // THEN it contains the dynamic import with default static
    const caddy = readCaddyfile();
    expect(caddy).toMatch(/import\s+\{\$FRONTEND_MODE:static\}-frontend/);
  });

  it('T-A04-DEFAULT: default is static when FRONTEND_MODE is unset', () => {
    // GIVEN the Caddyfile import directive
    // WHEN FRONTEND_MODE is not set
    // THEN the default value in the import is "static"
    const caddy = readCaddyfile();
    const importMatch = caddy.match(/import\s+\{\$FRONTEND_MODE:(\w+)\}-frontend/);
    expect(importMatch).not.toBeNull();
    expect(importMatch![1]).toBe('static');
  });

  it.todo('MANUAL: Caddy starts in prod mode when FRONTEND_MODE is unset');
  it.todo('MANUAL: Caddy proxies to vite:5173 when FRONTEND_MODE=dev');
});

