describe('REQ-A09: Environment Variable Updates', () => {
  it('T-A29: .env.example contains FRONTEND_MODE', () => {
    // GIVEN .env.example
    // WHEN inspected
    // THEN it contains FRONTEND_MODE
    const envFile = readEnvExample();
    expect(envFile).toMatch(/FRONTEND_MODE/);
  });

  it('T-A30: FRONTEND_MODE default is static', () => {
    // GIVEN .env.example
    // WHEN the FRONTEND_MODE line is inspected
    // THEN its value is static
    const envFile = readEnvExample();
    expect(envFile).toMatch(/FRONTEND_MODE=static/);
  });

  it('T-A31: .env.example has comment explaining FRONTEND_MODE values', () => {
    // GIVEN .env.example
    // WHEN inspected
    // THEN there is a comment near FRONTEND_MODE explaining valid values (dev/static)
    const envFile = readEnvExample();
    const lines = envFile.split('\n');
    const modeLineIdx = lines.findIndex((l) => l.includes('FRONTEND_MODE'));
    expect(modeLineIdx).toBeGreaterThanOrEqual(0);
    // Check for a comment on the same line or the line before
    const commentOnLine = lines[modeLineIdx].includes('#');
    const commentBefore = modeLineIdx > 0 && lines[modeLineIdx - 1].trim().startsWith('#');
    expect(
      commentOnLine || commentBefore,
      'FRONTEND_MODE should have an explanatory comment'
    ).toBe(true);
  });

  it('T-A32: existing variables are not removed from .env.example', () => {
    // GIVEN .env.example
    // WHEN compared to known existing variables
    // THEN none of the previously existing variables are removed
    const envFile = readEnvExample();
    // Sample of known variables from the base infrastructure (SPEC-20260407-001)
    const knownVars = [
      'REDIS_AUTH',
      'LANGFUSE_SECRET_KEY',
      'NEXTAUTH_SECRET',
      'SALT',
    ];
    for (const varName of knownVars) {
      expect(envFile, `${varName} should still be present`).toContain(varName);
    }
  });

  it('T-A09-CLICKHOUSE: .env.example contains CLICKHOUSE_PASSWORD=CHANGEME', () => {
    // GIVEN .env.example
    // WHEN inspected
    // THEN it contains CLICKHOUSE_PASSWORD=CHANGEME
    const envFile = readEnvExample();
    expect(envFile).toMatch(/CLICKHOUSE_PASSWORD=CHANGEME/);
  });
});
